#include <bits/stdc++.h>
using namespace std;
map<string,int> dist;
string s;
void Solve(){
	queue<string> q;
	queue<int> zero;
	q.push("123804765"),zero.push(4),dist["123804765"]=1;
	while(q.size()){
		string f=q.front(),tmp=q.front();
		int p=zero.front();
		q.pop(),zero.pop();
		if(p>=3){
			swap(f[p],f[p-3]);
			if(!dist[f])
				q.push(f),zero.push(p-3),dist[f]=dist[tmp]+1;
			swap(f[p],f[p-3]);
		}
		if(p<6){
			swap(f[p],f[p+3]);
			if(!dist[f])
				q.push(f),zero.push(p+3),dist[f]=dist[tmp]+1;
			swap(f[p],f[p+3]);
		}
		if(p%3>0){
			swap(f[p],f[p-1]);
			if(!dist[f])
				q.push(f),zero.push(p-1),dist[f]=dist[tmp]+1;
			swap(f[p],f[p-1]);
		}
		if(p%3<2){
			swap(f[p],f[p+1]);
			if(!dist[f])
				q.push(f),zero.push(p+1),dist[f]=dist[tmp]+1;
			swap(f[p],f[p+1]);
		}
	} 
} 
int main(){
	cin>>s;
	Solve();
	printf("%d",dist[s]-1);
	return 0;
}
